var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…사정상, 한동안 연락드리지 못한 점 사과드립니다.","JPN":"……都合上、しばらく連絡できなかった点、申し訳ございません。","ENG":"I’m sorry for staying silent for so long...","TWN":"…很抱歉，因為一些原因，許久未能聯絡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"벌써 시간이 꽤 지난 일이긴 합니다만…….","JPN":"もう随分前の出来事ではありますが……","ENG":"It's been quite some time but...","TWN":"雖然已經過有點久……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"정기 보고 형식상, 시간 경과대로 진술하도록 하겠습니다.","JPN":"定期報告の形式上、時間の経過順に述べさせていただきます。","ENG":"I’ll give you a timeline report in accordance with the official format.","TWN":"但我還是以定期報告的方式，按時間發生順序進行陳述。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"먼저, 가족 모임 당시 있었던 일입니다.","JPN":"まずは、家族会の時にあった出来事です。","ENG":"Let me start with what happened at the family meeting.","TWN":"首先是家族聚會時的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"예식을 마친 뒤 세대별로 회동을 가졌다는 건 알고 계실 겁니다.","JPN":"礼式の後、世代別の集まりがあったことはご存知でしょう？","ENG":"You may know that each generation holds its own meetings.","TWN":"您也知道，儀式過後會各自帶開討論。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"자제 분들도 각자 그룹 계열사를 맡고 있으니만큼, 사실상 경영 얘기가 주된 화제였죠.","JPN":"ご子息もそれぞれグループの系列会社を管理しているため、事実上経営の話が主な話題でした。","ENG":"Since they are running their own companies, the main topic of the meeting was their businesses.","TWN":"畢竟小姐、少爺們都有各自負責集團的分公司，所以大部分的話題都圍繞在公司經營上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"…그러니까 누님! 우리도 어렵다니까!","JPN":"……だから、姉さん！　うちも厳しいんだって！","ENG":"Sis, I’m telling you. We have our own issues!","TWN":"…我說大姊！我們也很為難啊！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"우리가 뭐 돈을 못 벌고 싶어서 못 벌어? 돈 벌 각이 안 나오잖아, 지금!","JPN":"こっちだってそりゃ、稼げるもんなら稼ぎたいよ！　でも今は八方塞がりなんだ！","ENG":"You think we’re not making money because we don’t want to? Look at the situation!","TWN":"你以為我們是嫌錢太多，不想賺錢嗎？就時機不好嘛！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이터니움 값은 치솟고 국제 정세는 맨날 불안한데 소비가 위축되는게 당연하지!","JPN":"エタニウムはどんどん高くなって、国家情勢はずっと不安定なこの状況で、消費が萎縮するのは当たり前だ！","ENG":"The cost of Eternium is going sky high, and the world is unstable. It’s obvious that consumption decreases!","TWN":"永恆之金的價格一直在漲，國際局勢又這麼不穩，消費萎縮是正常的嘛！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"무기 팔아야 하는 애가 그런 소리를 하니?","JPN":"武器商売をする人間が、そんなことを言ってどうするの？","ENG":"What? You’re selling weapons!","TWN":"賣武器維生的傢伙怎麼說這種話？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"그냥 속 시원히 말하지 그래? 뒤로 해 먹게 예산 좀 많이 책정해 달라고?","JPN":"もうはっきり言っちゃえば？　お小遣いが足りないから、もっと予算をくれって。","ENG":"Just be honest. You want a bigger budget so that you can fill your own pockets.","TWN":"你乾脆直說吧！想要多拿一些預算是吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"쳇, 그러는 누님도 푼돈이나 만지는 주제에 뭐가 잘났는데?","JPN":"ちっ、そういう姉さんだって、はした金しか稼げないくせして偉そうだな。","ENG":"Hmpf, are you that good? You only make tiny money, don't you? ","TWN":"嗟！我說大姊，你以為你們是賺多少，在那邊囂張什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 너 지금 뭐라고 했어?","JPN":"何ですって？　あんた今なんて言った？","ENG":"What did you just say?","TWN":"你說什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"할배 죽고 나서 알파트릭스 주가 떨어지는 게 원 데이 투 데이도 아니고….","JPN":"ジジイが死んで、アルファトリックスの株価が下落したのも昨日今日のことじゃねぇ……","ENG":"Alphatrix stock is dropping like a stone since grandpa died...","TWN":"爺爺死掉後，阿爾法崔克斯的股價就一直在跌…"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"우리 세대에서 올해 적자 면한 녀석이 있기는 해?","JPN":"俺らの世代で今年、赤字じゃないやつなんているのかよ。","ENG":"Is there any company which is actually in the black nowadays?","TWN":"我們當中有反虧為盈的傢伙嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저기……. 오라버니.","JPN":"あの……お兄様。","ENG":"Um... Jaehyuk.","TWN":"那個……大哥。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐야, 괴물. 넌 옆에서 실실 쪼개고나 있어.","JPN":"なんだ、化け物。お前は黙ってへらへらしとけ。","ENG":"What, you monster? You just keep smiling and saying nothing.","TWN":"幹嘛，怪物！你就給我在旁邊負責笑就好！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 뭔가 착오가 있는 것 같아서요.","JPN":"いえ、何か勘違いされているようなので。","ENG":"No, I believe you’re mistaken.","TWN":"不是的，好像有什麼誤會？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희 알파트릭스 이노베이션은 올해 상반기도 흑자래요. 하반기 전망도 밝은 편이고요.","JPN":"私のアルファトリックス・イノベーションは今年の上半期も黒字だそうです。下半期の展望も明るいですし。","ENG":"Alphatrix Innovation is in the black. Also we’re expecting a positive earnings report for the second half of the year.","TWN":"我們阿爾法崔克斯改革今年上半年是有盈餘的，下半年也很樂觀喔。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"…그래서, 너 잘났다 이거냐?","JPN":"……だからなんだ、自分は凄いってか？","ENG":"Are you trying to bust my chops here?","TWN":"…所以你想說的是你好棒棒嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아. 그런 의미로 말씀드린 건 아니에요.","JPN":"あ、そういった意味でお話したわけではありません。","ENG":"No, I didn’t mean that.","TWN":"喔，我不是這個意思。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"넌 당연히 돈을 벌어야지. 태스크포스는 치안이 불안해질수록 수요가 높아지니까.","JPN":"お前は稼げて当然だ。タスクフォースは治安が悪化するほど需要が高まるからな。","ENG":"Of course, you do. A TASKFORCE company like you gets high demand as public safety gets worse.","TWN":"你當然賺錢囉！特遣勢力不是治安越差收入越高嗎！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"돈 많이 벌어서 좋겠네. 지옥에서 찜질하고 있을 할배도 기특하게 생각하겠다, 야.","JPN":"稼げててよかったな。地獄で温まってるジジイも、さぞ喜んでるだろうよ。","ENG":"So good for you, I’m sure our grandpa is beaming in hell.","TWN":"賺那麼多錢真好～在地獄裡掙扎的爺爺也會誇你很棒吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럴 리가요. 할아버님은 천국에 계실 거예요.","JPN":"そんなわけありません。お祖父様は天国にいらっしゃるはずです。","ENG":"No, grandfather is in heaven, I’m sure of it.","TWN":"怎麼可能呢？爺爺應該是在天堂。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"웃기시네. 그 돈벌레 있는 데가 지옥인데.","JPN":"ばか言ってんじゃねぇ。あの金の亡者がいれば、そこが地獄だろうが。","ENG":"Bollocks. That miser was hell itself.","TWN":"笑死，那個視錢如命的傢伙當然是在地獄！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 이건 어때. 잘나신 네가 나한테 예산 좀 좀 나눠주는 거야.","JPN":"あ、ならこうしようぜ。優秀なお前が俺に、予算を少しばかり分け与えるんだ。","ENG":"Oh, wait. How about you give me some of your money, since you’re operating in the black?","TWN":"不然這樣如何？你這麼棒，不如就分點預算給我吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"핏줄 좋다는 게 뭐겠어? 응?","JPN":"ほら、俺ら家族だろ？　なあ？","ENG":"We’re family, right?","TWN":"要不然跟你當兄妹有什麼好處？你說說看啊？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"회장님이 살아 계셨을 때는 이렇지 않았는데…….","JPN":"会長がご存命の頃はこんなことなかったのに……","ENG":"This sort of thing would never have happened if the President was still alive...","TWN":"會長還在世時不是這樣的……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스가 이런 망나니들 회사놀이로 전락하다니.","JPN":"アルファトリックスが、こんなろくでなしどもの会社ごっこにまで転落するなんて。","ENG":"These ruffians are ruining Alphatrix.","TWN":"阿爾法崔克斯竟然會淪落成這群人耍流氓的地方！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"여기서는 아가씨께…","JPN":"ここは一つ、お嬢様に……","ENG":"I should talk to Jia...","TWN":"小姐…"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 좋아요!","JPN":"はい、いいですよ！","ENG":"Okay!","TWN":"好，沒問題！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"…으, 으응?","JPN":"……え、ええ？","ENG":"Huh?","TWN":"…嗯？你說什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 말씀하셨어요. 형제끼리는 서로 돕고 살아야 한다고요.","JPN":"お祖父様はこう言いました。兄弟は助け合うものだと。","ENG":"Our grandfather said family members should help each other.","TWN":"爺爺有說，兄弟姊妹之間必須互相幫助。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스 이노베이션은 올해 본사로부터 예산을 받지 않겠습니다.","JPN":"アルファトリックス・イノベーションは今年、本社からの予算を受け取りません。","ENG":"We, Alphatrix Innovation, will not take any money from headquarters this year.","TWN":"阿爾法崔克斯改革今年不會拿總公司的預算。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"잠시만요, 아가씨! 저는 들은 적 없는 결정입니다!","JPN":"待ってください、お嬢様！　私はそのことについて一切耳にしておりません！","ENG":"Wait, Miss Jia! I was not informed of this!","TWN":"小姐，先等一下！怎麼沒先跟我商量！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"네 비서는 저렇게 말하는데…… 진심으로 하는 소리냐?","JPN":"お前の秘書はああ言っているけど……本気で言ってんのか？","ENG":"Says your secretary. Do you really mean it?","TWN":"你秘書那麼說欸……你確定嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럼요. 물론이죠.","JPN":"ええ、もちろんです。","ENG":"Of course.","TWN":"當然，我確定。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 오라버니, 저 한 가지 부탁드려도 될까요?","JPN":"それからお兄様。一つ、お願いをしてもよろしいでしょうか？","ENG":"Also, may I ask you something?","TWN":"大哥，我可以拜託你一件事嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 아가씨! 헤비암즈의 지분을 매입하시겠다니요!","JPN":"ユイお嬢様！　ヘビーアームズの持ち分をお買取りになるなんて！","ENG":"Miss Jia, you can’t just purchase Heavyarms stocks!","TWN":"小姐！怎麼可以買入重武裝的持股！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"경쟁력이 고갈되어 상장 폐기 수순을 밟고 있는 곳입니다. 당장 결정을 철회해 주세요.","JPN":"競争力を失い、上場廃止の手続きを行っている会社です。今すぐ決定を取り消してください。","ENG":"That company has lost its drive and is about to be delisted from the market. Please reconsider.","TWN":"那根本就是一間沒有任何競爭力，準備要退市的公司！請收回決定！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말요? 처음 듣는 얘기네요?","JPN":"そうなのですか？　初耳ですね。","ENG":"Really? I didn’t know that.","TWN":"真的嗎？這還是我第一次聽說呢？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"처음 들으신다니요? 그럼 대체 어째서…!","JPN":"初耳？　では、いったいどうして……！","ENG":"You didn’t know? Then you should...","TWN":"竟然是第一次聽說？那小姐怎麼會…！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 말씀하셨어요. 노력하는 사람들에게는 그에 걸맞은 대우를 해야 한다고요.","JPN":"お祖父様はこう言いました。努力する者には、それに見合う待遇を与えるべきだと。","ENG":"My grandfather said people should be paid for their efforts.","TWN":"我爺爺有說，對於努力的人，就應該給予相對等的待遇。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"헤비암즈는 지속적인 경영 악화와 신병기 계약 결렬… 최근에는 방산 비리까지 터졌습니다.","JPN":"ヘビーアームズは持続的な経営悪化及び、新兵器契約の決裂……最近は防衛産業の不正まで発覚しました。","ENG":"Heavyarms is constantly operating in red, and its new weapons development project contract went awry. Not to mention the corruption scandal...","TWN":"重武裝不只是經營持續惡化，新武器的合約也不成功…最近還爆發國防工業舞弊事件。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그런 회사가 대체 무슨 노력을 한다는 거죠?","JPN":"そんな会社がいったいどんな努力をしていると？","ENG":"And you see *effort* in all of that?","TWN":"這種公司到底付出什麼努力？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"현장 기술자 분들은 밤낮으로 노력하고 계시더라고요.","JPN":"現場の技術者たちは、寝る間も惜しんで努力されていました。","ENG":"I saw the engineers working very hard, night and day.","TWN":"現場的技術人員都在日夜努力工作中。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"조금만 도와드리면 분명 멋진 모습을 보여 주실 거예요.","JPN":"少し手を差し伸べれば、きっと素晴らしい成果を見せてくださるでしょう。","ENG":"I’m sure they will do better if we help them.","TWN":"我相信只要稍微助他們一臂之力，他們一定會煥然一新的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"겨우…… 겨우 그런 이유로 지분을 매입하셨다고요?","JPN":"たった……たったそれだけの理由で、持ち分を買い取られたのですか？","ENG":"You... you purchased the stock for that reason?","TWN":"就只是……因為這種理由，就買入持股嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"자칫하면 저희는 회생 불가능한 손실을 떠맡아야 하는데도요?","JPN":"下手すると私たちは、再起不能なまでの損失を抱える羽目になるのですよ？","ENG":"It could ruin us financially.","TWN":"萬一有個差池，說不定會賠上我們整間公司，這樣你也願意嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 잘하실 거라고 믿고 있어요.","JPN":"はい、うまくやってくださると信じています。","ENG":"I’m sure they will do fine.","TWN":"是，我相信他們可以的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 때는 지아 아가씨가 큰 실책을 저질렀다고 여겼습니다.","JPN":"当時はユイお嬢様が誤った判断をされたと思っていました。","ENG":"I thought Jia made a huge mistake back then.","TWN":"當時我認為小姐根本是鑄下大錯。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"게다가 소문이 퍼졌는지, 여기저기서 투자를 부탁하는 자들이 엉겨 붙더군요.","JPN":"それに噂が広まったのか、あちこちで投資してくれという人たちが接触してきたのです。","ENG":"And when the rumor spread, people came to her asking for investment.","TWN":"而且後來不知道是不是消息傳開來的關係，開始有許多人來拜託小姐投資。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 아가씨는 그중에도 상식적으로는 가망이 희박한 곳에만 투자하겠다고 하셔서 저와 마찰이 많았습니다.","JPN":"ユイお嬢様は、見込みのない会社にばかり投資されるので、私とは意見がよく食い違っていました。","ENG":"She always chose companies with no hope, and I often argued with her.","TWN":"小姐說，在那些來找她投資的公司當中，她只投資那些客觀上看起來沒什麼前景的公司。也因為這樣，當時我和小姐經常發生摩擦。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"거짓말이 아닌 것 같다느니, 회사 건물이 좋아 보인다느니……. 얼토당토 않은 이유뿐이었으니까요.","JPN":"嘘ではなさそうだの、会社の建物がオシャレだの……話にもならない理由ばかりでした。","ENG":"The reasons that she chose these companies were just ridiculous... \\"They seem honest\\", \\"their buildings look nice\\", something like that. ","TWN":"小姐應該不是在說謊，但她投資的原因只是因為建築物看起來很漂亮……這種荒謬的理由。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그런데 아가씨가 헤비암즈의 주주가 되어 경영에 간섭한 지 몇 개월 안 지나 일이 터졌죠.","JPN":"ですが、お嬢様がヘビーアームズの株主になり、経営に干渉し始めて数か月であることが起きました。","ENG":"Then, a few months after she purchased the Heavyarms stock, it happened...","TWN":"後來小姐成為重武裝的股東，在她介入經營後沒多久，事情就發生了。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"관리국 주최 방산 산업회에서 헤비암즈의 신형 소총탄 프로젝트가 주목을 받았더군요.","JPN":"管理局主催の防衛産業界で、ヘビーアームズの新型小銃弾プロジェクトが注目されたのです。","ENG":"Heavyarms’ newly developed rifle ammo project became the center of attention at the Administration’s defense industry fair.","TWN":"在管理局主辦的國防工業產業會上，重武裝的新型步槍子彈計畫受到關注。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아시다시피 당시 헤비암즈의 주가는 하한가 갱신을 마치고 단기간에 40% 가량 상승했습니다.","JPN":"ご存じのとおり、当時下落する一方だったヘビーアームズの株価が、短期間で40％近く上昇しました。","ENG":"As you know, its stock price skyrocketed by 40% after bottoming out.","TWN":"您也知道，當時重武裝的股價跌停板後，在短時間內就漲40%左右。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"성공 요인은 아가씨 말처럼 기술진들의 수준이 나쁘지 않았다는 점.","JPN":"成功の要因は、お嬢様の仰っていたように技術者のレベルが悪くなかった点。","ENG":"The project was successful, mainly because the engineers were good, as she said.","TWN":"而成功的關鍵就如小姐所言，是因為技術人員的能力不差。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그리고 기존 경영진들이 기업을 매각할 방법에만 몰두하는 동안……","JPN":"そして、当時の経営陣が企業を売却する方法探しに躍起になっている間……","ENG":"And while the management was focusing on selling the company...","TWN":"因為就在原本的經營團隊只忙著想要賣掉公司時……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 기술진들은 상부 지시로 도입하던 불안정한 신기술 대신 본래 주력이었던 탄환 제조에 집중했다는 점입니다.","JPN":"技術者たちは上層部の指示で導入していた不安定な新技術の代わりに、本来の主力分野であった弾丸の製造に集中していたという点です。","ENG":"The engineers focused their efforts on the ammo project, where their expertise lies, rather than working on the unstable new technology that the management wanted.","TWN":"那群技術團隊沒有照著上面的指示，把心力花費在不穩定的新技術上，而是專注於原本的主力，也就是彈藥製造上。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저는 단순히 우연의 일치라고만 생각했습니다.","JPN":"私は単なる偶然の一致だとばかり考えていました。","ENG":"I thought it was just a coincidence.","TWN":"我當時認為這只是巧合而已。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……다른 사람들처럼요.","JPN":"……他のみんなのように。","ENG":"...Just like others.","TWN":"……就如同他人的想法一樣。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 한 번만 봐 주면 안 되냐? 이제 이득 볼 만큼 봤잖아, 응?","JPN":"なあ、ユイ。もう勘弁してよ。十分利益も出ただろ？","ENG":"Jia, please help me this time. You must have had enough.","TWN":"小佳，你就行行好嘛～反正你也賺夠多了吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 갑자기 찾아와서 무슨 말씀이세요, 오라버니?","JPN":"はい？　急に来られて、何を仰るのですか？　お兄様。","ENG":"Hm? What are you talking about?","TWN":"什麼意思？大哥你突然來找我說這些是什麼意思？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"에이. 모른 척하지 말고. 당연히 내 회사 지분 얘기지.","JPN":"ほら、知らんぷりするなよ。俺の会社の持ち分の話に決まってるだろ。","ENG":"Stop pretending you don’t understand. I’m talking about my stock.","TWN":"哎唷～你少裝了啦，當然是在說我公司持股的事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"너 처음부터 다 알고 접근한 거잖아, 그치?","JPN":"お前、最初から全部知ってて近づいてきたんじゃないのか？","ENG":"You knew from the beginning, didn’t you?","TWN":"你根本打從一開始就知情，才願意買下持股的吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……역겨운 자식.","JPN":"……外道め。","ENG":"That disgusting bastard.","TWN":"……噁心的傢伙！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"노른자위 같은 회사를 망쳐 놓고 헐값에 팔아넘기더니, 이제 와서 돌려 달라고?","JPN":"中核のような会社を台無しにした挙句、捨て値で売り付けておいて、いまさらそれを返せですって？","ENG":"You ruined a perfectly fine company, sold it to us for a giveaway price, and now you want it back?","TWN":"把最好的公司搞砸後賤價售出，現在還有臉來要回去？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 아아! 물론 그냥 지분을 돌려받겠다는 건 아니야!","JPN":"おっと！　もちろんただで返してもらうつもりはない！","ENG":"Oh, I don’t mean you should give them back to me without conditions!","TWN":"好好好！我當然不會要你白白還給我！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"지금 주식 가격의 10%는 더 쳐서 줄게.","JPN":"今の株価より10％上乗せして買うからさ。","ENG":"I will pay 10% on top of the current stock price.","TWN":"我用比目前股價再高10%的價格跟你買！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"으음……. 그렇지만…….","JPN":"うーん……ですが……","ENG":"Hm... But...","TWN":"嗯……可是……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 아니면 13%는 어때?","JPN":"じゃ、じゃあ13％はどうだ？","ENG":"Or 13%?","TWN":"好好好，不然這樣，13%怎麼樣？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"에잇, 기분이다! 15%까지 더 얹어 줄게!","JPN":"ええい、15％にしよう！","ENG":"Okay, I’m feeling generous today. 15%!","TWN":"好啦！一口氣！15%啦！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨……. 그런 게 아니라…….","JPN":"いえ、そうではなくて……","ENG":"No, I don’t mean...","TWN":"不是的……我不是那個意思……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"오라버니, 지금 주식을 다시 사들이시는 건 조금…….","JPN":"お兄様、今株を買いなおすのはいかがなものかと……","ENG":"You can’t just take the stocks back now...","TWN":"大哥，你現在要把股份買回去有點……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이런 젠장! 변명 집어치워! 내가 네 속을 모를 줄 알아!","JPN":"ちくしょう！　言い訳はよせ！　俺がお前の狙いを知らないとでも？","ENG":"God damn it! Shut up! You think I don’t know what you’re thinking?","TWN":"該死！少跟我廢話一堆！你以為我不知道你在想什麼嗎！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"대체 얼마나 더 올려 먹어야 직성이 풀리는데, 이 괴물 같은 년아!","JPN":"いったいいくら稼げば気が済むんだ！　この化け物が！","ENG":"How much more do you want, you monstrous bitch!","TWN":"你這怪物！你到底想賺多少才甘願！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"헤비암즈는 원래 내 거였어! 얼마나 덤탱이를 씌우려는 거야, 대체!","JPN":"ヘビーアームズはもともと俺のだったんだぞ！　こんなのぼったくりだ！","ENG":"Heavyarms was mine from the beginning! You can’t rip me off like this!","TWN":"重武裝本來就是我的！你到底想霸佔著到什麼時候！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이제야 연기를 그만뒀군.","JPN":"やっと芝居をやめたわね。","ENG":"He finally stopped acting.","TWN":"露出真面目了吧！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저렇게 폭언을 퍼붓는데 아가씨께서 지분을 넘기실 리 없어.","JPN":"あれほど暴言を浴びせられて、お嬢様が持ち分を渡すはずないわ。","ENG":"She would never give the stocks away to that rude man.","TWN":"說話那麼不客氣，小姐怎麼可能把股份還給你！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……알겠어요, 재혁 오라버니.","JPN":"……わかりました、お兄様。","ENG":"Okay, Jaehyuk.","TWN":"……我知道了，大哥。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 말씀하셨어요. 가족끼리는 사이 좋게 지내야 한다고요.","JPN":"お祖父様はこう言いました。家族は円満であるべきだと。","ENG":"Our grandfather said family members should be kind to each other.","TWN":"爺爺有說，家人之間要相親相愛。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"헤비암즈의 지분을 전량 돌려드릴게요. 돈은 시세로만 주셔도 돼요.","JPN":"ヘビーアームズの持ち分をすべてお返しします。金額は相場どおりで結構ですよ。","ENG":"You can take all the Heavyarms stocks at the market price.","TWN":"重武裝的持股全部還給你，錢就用市價去算就好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아, 아가씨!?","JPN":"お、お嬢様！？","ENG":"Miss Jia!?","TWN":"小…小姐？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"흥. 처음부터 그렇게 나올 것이지, 꼭 싫은 소리를 하게 만들어.","JPN":"ふん、最初からそうしろってんだ。無駄に怒らせやがって。","ENG":"Hah, why didn’t you say so in the first place? Then I wouldn’t have said such mean things to you.","TWN":"哼，早這麼做不就好了，非得逼我口出惡言！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"재수 없는 괴물 자식. 그러니까 이딴 데 처박혀 살지.","JPN":"気色の悪い化け物め。そんなんだから、こんなとこに放り込まれてんだ。","ENG":"You are a monster that you rot here.","TWN":"真是噁心的怪物！難怪你會窩在這種地方！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨, 대체 왜 저런 작자에게 지분을 넘기신 거죠?","JPN":"お嬢様、いったいなぜあんなやつに持ち分を渡したのですか？","ENG":"Miss Jia, why did you give him the stocks?","TWN":"小姐，你為什麼要把股份還給那種傢伙呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어쩔 수 없었어요. 할아버님께서 말씀하셨거든요.","JPN":"仕方ありません。お祖父様はこう言いました。","ENG":"I couldn't help it. My grandpa said...","TWN":"沒辦法，因為我爺爺有說，"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"도움을 거절하는 사람의 의사를 무시하고 도와 주는 건 무례한 짓이라고요.","JPN":"助けを拒む者の意志を無視し助けることは無礼なことだと。","ENG":"It’s rude to help someone who doesn’t want your help.","TWN":"無視對方的意願，強加在對方身上的好意，是有失禮貌的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 말씀은…… 신재혁에게 도움이 필요하다는 뜻인가요?","JPN":"では……ヒメノ・ダイチに助けが必要だということですか？","ENG":"Do you mean... that Shin Jaehyuk needed your help?","TWN":"小姐的意思是……沈赫拒絕你的好意？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 지난달부터 어째선지 전세계적으로 시장의 이터니움 공급량이 조금 줄어들었거든요.","JPN":"はい、先月からなぜか全世界の市場でエタニウムの供給量が少し減ったのです。","ENG":"Yes. For some reason, the global Eternium supply has been decreasing since last month.","TWN":"是的，不知道是什麼原因，從上個月開始，全世界的永恆之金供應量開始下滑。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……네?","JPN":"……え？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"짐작하시겠지만, 그 뒤 국제적인 <color=#ffd34c>테러 사태</color>로 인해 이터니움 원가가 치솟게 되었습니다.","JPN":"もうおわかりでしょうが、その後国際的な<color=#ffd34c>テロ事態</color>により、エタニウムの原価が高騰しました。","ENG":"As you know, the international <color=#ffd34c>terrorist attack</color> caused an increase in the price of Eternium.","TWN":"您應該也有猜到，在那之後因為國際性<color=#ffd34c>恐怖事件</color>，導致永恆之金價格上漲。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그리고 헤비 암즈는 운이 좋지 않았습니다.","JPN":"それに加えヘビーアームズには運がついていませんでした。","ENG":"But Heavyarms wasn’t very lucky.","TWN":"而重武裝的運氣不怎麼好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"시장이 안정세를 찾기 전에, 신형 소총탄의 이터니움 함량이 가격 경쟁력의 발목을 잡았죠.","JPN":"市場が安定する前に、新型小銃弾のエタニウム含量が価格競争の足を引っ張ったのです。","ENG":"Before the market stabilized, the newly developed ammo went down because it had too much Eternium in it, and lost its competitiveness as the price went up.","TWN":"在市場穩定前，新型步槍子彈的永恆之金含量，導致價格沒有競爭力。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이를 해결하는 과정에서 경영진이 다시 개입하는 바람에, 기존 설계의 이점은 사라졌고…….","JPN":"これを解決する過程で経営陣が再び介入したことにより、既存設計の利点は消え……","ENG":"Then management interfered again, and the engineers had to change the plan, which in turn resulted in the plan losing its merit.","TWN":"為了解決這個問題，經營團隊又再次介入，原本設計的優點蕩然無存……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"헤비암즈의 경영 상황도, 주가도 원점으로 돌아온 상태입니다.","JPN":"ヘビーアームズの経営状況も、株価も今は元に戻っています。","ENG":"So, the financial status of Heavyarms returned to where it started, including the stock price.","TWN":"無論是重武裝的經營狀況，或是股價又回到了原點。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그리고 기대했던 수익은, 아가씨께서 제 반대를 무릅쓰고 투자했던 곳에서 창출되었죠.","JPN":"そして期待された収益は、お嬢様が私の反対を押しきり投資したところで生まれました。","ENG":"And Jia gained her profit from other companies that she invested... the companies I went against.","TWN":"而期待的獲利，則是從小姐不顧我的反對投資的公司中產生的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"단순한 우연이라고 치부할 수도 있겠지만…","JPN":"単なる偶然と片づけることもできるでしょうが……","ENG":"Maybe it’s just a coincidence...","TWN":"雖然這也可以說是巧合…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아직도 모르겠나, 이 실장.","JPN":"まだわからんか、シノザキ室長。","ENG":"Don’t you understand, Jin?","TWN":"室長，你還不明白嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"옛날부터 그 괴물이 엮인 사건에 우연 따위 없었어.","JPN":"昔からあの化け物が関わった事件に偶然なんてなかった。","ENG":"That monster never operates on coincidences.","TWN":"從以前開始，那個怪物插手的事，沒有一件是巧合的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"전부 신지아라는 <color=#ffd34c>버그</color>가 만들어낸 결과지.","JPN":"全てヒメノ・ユイという<color=#ffd34c>バグ</color>が生み出した結果だよ。","ENG":"Shin Jia... that <color=#ffd34c>bug</color> is the main causal of all these events.","TWN":"全都是名為沈佳的<color=#ffd34c>BUG</color>創造出的結果。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 결론은, 조금 앞서 나가신 것 아닐까요?","JPN":"そう結論づけるには、少し早すぎませんか？","ENG":"I think you’re jumping to conclusions.","TWN":"就結論而言，您還是稍微超前不是嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아니. 그 괴물을 본 시간은 자네보다 내가 훨씬 길어.","JPN":"いいや。あの化け物を見てきた時間は、君より私のほうがずっと長い。","ENG":"No, I’ve been watching that monster much longer than you.","TWN":"不，我認識那怪物的時間比你還長。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"나는……. 아직도 그 계집애를 처음 봤을 때 느낀 섬뜩함을 잊을 수가 없어.","JPN":"私は……いまだにあの小娘を最初見たときに感じた、身の毛もよだつ感覚を忘れることができずにいるのだ。","ENG":"I still remember that she gave me the creeps when I first saw her.","TWN":"我……到現在還忘不了，第一次看到那丫頭時的恐懼感。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내 아내가 그린 그림을 한 번 보고 그보다 더 잘 그렸어.","JPN":"私の妻が描いた絵をひと目見て、あの小娘はより美しい絵を描いてみせた。","ENG":"She looked at my wife’s painting, and recreated it right away, with even better quality.","TWN":"她只看過我內人畫的畫一次，就畫出比內人更厲害的畫。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"서류 한 장 보고 사촌이 운영하던 회사가 분식회계를 저질렀다는 걸 알아채더군.","JPN":"少し書類を見ただけで、従妹が運営していた会社が粉飾決算をしていたことを見抜いた。","ENG":"She also noticed an accounting fraud in my cousin’s company, just by looking at a single paper.","TWN":"只看到一頁資料，就發現親戚公司作假帳的事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"워치를 얻을 때도 마찬가지였어.","JPN":"ウォッチを手に入れたときもそうだ。","ENG":"It also happened when she got the Watch.","TWN":"獲得能量環的時候也是一樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내 동생이 각성한 걸 보자마자 녀석 손에 워치가 나타났어. 바로 우리 눈앞에서.","JPN":"私の妹が覚醒したのを見た途端、やつの手にウォッチが現れた。私たちの目の前で。","ENG":"When she saw my sister awaken, she got the Watch in her hand. Right in front of us.","TWN":"她一看到我妹妹覺醒後，在眾目睽睽之下，她的手上就立刻出現能量環。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"어떻게 했냐고 물어 보면 돌아오는 대답은 늘 같았지.","JPN":"どうやったのかを聞くと、帰ってくる答えはいつも決まって一緒だった。","ENG":"When I asked how she did it, she always gave me the same answer.","TWN":"問她怎麼辦到的，總是得到千篇一律的回答。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"<color=#ffd34c>왜 못하는지 모르겠다</color>고.","JPN":"<color=#ffd34c>どうしてできないんですか？</color>、と。","ENG":"<color=#ffd34c>Why can’t you do it?</color>","TWN":"<color=#ffd34c>為什麼辦不到呢？</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……예전이나 지금이나 같으시군요.","JPN":"……今も昔も変わりませんね。","ENG":"...I see she hasn’t changed.","TWN":"……現在和以前都沒變呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"한 번은 우연이고 두 번은 필연이고, 세 번은 운명이라고 하던가?","JPN":"一回目は偶然で二回目は必然、三回目は運命と言ったか。","ENG":"Once, you call it a coincidence, twice it’s meant to be, and the third time, you call it destiny.","TWN":"一次是巧合，兩次是必然，三次是命運嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그럼 <color=#ffd34c>저건</color> 뭐지? 한 번도 실패한 적 없고, 원하는 건 뭐든 꿰뚫어 보는 저건?","JPN":"では<color=#ffd34c>あれ</color>はなんだ？　なんでも完璧にこなし、欲しいものはなんでも手に入れるあの能力は！","ENG":"What do you call <color=#ffd34c>it</color>? It never experienced any failure, and always gets what it wants.","TWN":"<color=#ffd34c>那傢伙</color>是怎樣？從來沒有失敗過，好像可以看穿任何事一樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네, 인간이 왜 사회를 이루고 사는 줄 아나?","JPN":"君、人間がなぜ社会を形成し生きるのか知っているか？","ENG":"Do you know why people build a society?","TWN":"你知道人類為什麼會組織社會嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"인간 하나하나는 한없이 약해서야.","JPN":"ひとりでは、どうしようもなく脆いからだ。","ENG":"That’s because each individual is too weak.","TWN":"因為人一個比一個還弱。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래서 서로의 약점을 보완하려고 배우자를 만나고, 가족을 이루고, 사회를 형성하지.","JPN":"だからお互いの弱点を補うため配偶者を選び、家族を成し、社会を形成する。","ENG":"So we meet others, make families, and build a society to make up for those weaknesses.","TWN":"所以為了互補，要遇見配偶，要組織家庭，要形成社會。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"하지만 그 괴물은 달라.","JPN":"だが、あの化け物は違う。","ENG":"But that monster is different.","TWN":"但那個怪物不是。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"지나칠 만큼, 불쾌할 만큼 우월해.","JPN":"あまりにも……気味が悪いほど優秀だ。","ENG":"That thing is way too superior, and it’s unpleasant.","TWN":"她過分厲害到令人討厭！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"형님은 그 괴물을 완벽히 통제할 수 있다고 믿었지만……. 만약의 상황에는 늘 대비해야 한다고 했지.","JPN":"兄さんはあの化け物をコントロールできると信じていたが……もしもの状況には常に備えるべきだと言っていた。","ENG":"My brother believed that he could control the monster... but he always had a contingency plan.","TWN":"大哥雖然認為可以完美地控制那個怪物……但也說過必須要做好預防措施。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"난 형님을 싫어하지만 그 말에는 동의하네.","JPN":"私は兄さんのことを好いてはいないが、その言葉には同意している。","ENG":"I didn’t like my brother, but I agreed with him on that issue.","TWN":"我是討厭大哥，但我認同他說的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"지금은 순진한 척 가식 떨고 있어도, 그런 괴물이 우리 같은 인간을 이해할 리가 없거든.","JPN":"今は無垢なふりをしているが、あんな化け物が我々人間を理解するわけがない。","ENG":"Even though that thing is pretending to be innocent, I know it could never understand us humans.","TWN":"她現在裝得一副天真無害的樣子，但那個怪物才不可能理解我們這種人！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"흠. 일단은 좌천인 모양새인데 여전히 가지고 있군. 그 <color=#ffd34c>만년필</color>.","JPN":"ほう……一応左遷という形になっているのに、相変わらず持っているのか。その<color=#ffd34c>万年筆</color>を。","ENG":"Oh, I see you still have it with you, even after you were demoted. That <color=#ffd34c>fountain pen</color>.","TWN":"嗯，雖然好像被降職的樣子，但你還是帶著呢！那支<color=#ffd34c>鋼筆</color>。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네… <color=#ffd34c>더 나은 세상을 위해</color>.","JPN":"はい……<color=#ffd34c>より良い世界のために</color>。","ENG":"Yes... <color=#ffd34c>For a better world</color>.","TWN":"是…<color=#ffd34c>為了更好的未來</color>。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래, 형님이 늘 입버릇처럼 중얼거리던 말이지.","JPN":"そう、兄さんが口癖のように言っていた言葉だ。","ENG":"Right, my brother always said that.","TWN":"嗯嗯，大哥也常把這句話掛在嘴邊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"하지만 나는 그렇게 생각하네, 이 실장.","JPN":"だが、私はこう思っているよ、シノザキ室長。","ENG":"But I think differently, Jin.","TWN":"但李室長，我是這麼想的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"정말로 더 나은 세상을 위해서라면…","JPN":"心からより良い世界を願うなら……","ENG":"If you really want a better world...","TWN":"要落實為了更好的未來…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그런 괴물부터 이 세상에서 없애 버려야 한다고.</color>","JPN":"<color=#ff3636>あの化け物を、この世から消し去るべきだ。</color>","ENG":"<color=#ff3636>You have to get rid of the monster first.</color>","TWN":"<color=#ff3636>就必須先把那個怪物從世界上除掉。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};